// 1. Sadə String Enums
enum Color {
  Red = "RED",
  Green = "GREEN",
  Blue = "BLUE"
}
const favoriteColor: Color = Color.Green;
console.log(favoriteColor); // Çıxış: GREEN

// 2. String Enums funksiyalarda
enum Direction {
  Up = "UP",
  Down = "DOWN",
  Left = "LEFT",
  Right = "RIGHT"
}
function move(direction: Direction): string {
  switch (direction) {
    case Direction.Up: return "Yuxarı hərəkət";
    case Direction.Down: return "Aşağı hərəkət";
    default: return "Hərəkət yoxdur";
  }
}
console.log(move(Direction.Up)); // Çıxış: Yuxarı hərəkət

// 3. String Enums ilə interfeyslər
interface User {
  id: number;
  favoriteColor: Color;
}
const user: User = { id: 1, favoriteColor: Color.Blue };
console.log(user); // Çıxış: { id: 1, favoriteColor: "BLUE" }

// 4. String Enums ilə union tipləri
type Action = Direction | "STOP";
function handleAction(action: Action): string {
  if (action === "STOP") return "Dayan";
  return move(action);
}
console.log(handleAction("STOP")); // Çıxış: Dayan
console.log(handleAction(Direction.Left)); // Çıxış: Hərəkət yoxdur

// 5. Const String Enums
const enum Role {
  Admin = "ADMIN",
  User = "USER",
  Guest = "GUEST"
}
const userRole: Role = Role.Admin;
console.log(userRole); // Çıxış: ADMIN

// 6. String Enums ilə type aliases
type Status = "PENDING" | "APPROVED" | "REJECTED";
interface Application {
  id: string;
  status: Status;
}
const app: Application = { id: "A001", status: "PENDING" };
console.log(app); // Çıxış: { id: "A001", status: "PENDING" }

// Sadə mağaza sistemi
enum ProductStatus {
  InStock = "STOCK",
  OutOfStock = "OUT",
  Discontinued = "DISCONTINUED"
}
interface Product {
  id: string;
  name: string;
  status: ProductStatus;
}
class ProductItem implements Product {
  id: string;
  name: string;
  status: ProductStatus;
  constructor(id: string, name: string, status: ProductStatus) {
    this.id = id;
    this.name = name;
    this.status = status;
  }
  getDetails(): string {
    return `${this.name} (ID: ${this.id}, Status: ${this.status})`;
  }
}
const laptop = new ProductItem("P001", "Laptop", ProductStatus.InStock);
console.log(laptop.getDetails()); // Çıxış: Laptop (ID: P001, Status: STOCK)

// Enum ilə funksiya
function checkAvailability(status: ProductStatus): string {
  switch (status) {
    case ProductStatus.InStock: return "Mövcuddur";
    case ProductStatus.OutOfStock: return "Mövcud deyil";
    case ProductStatus.Discontinued: return "İstehsal dayandırılıb";
    default: return "Bilinməyən status";
  }
}
console.log(checkAvailability(ProductStatus.OutOfStock)); // Çıxış: Mövcud deyil

